class HitCounter:
    def __init__(self):
        self.hits = []
    def hit(self, timestamp):
        self.hits.append(timestamp)
    def getHits(self, timestamp):
        while self.hits and self.hits[0] <= timestamp - 300: self.hits.pop(0)
        return len(self.hits)

